member.example:
Bind the AudioSource min/max distance property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceMinMaxDistanceBinder _minMaxDistance;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector2 _minMaxDistance;
    }


Bind the AudioSource min/max distance property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceMinMaxDistanceBinder MinMaxDistance =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector2 _minMaxDistance;
    }

Switch the AudioSource min/max distance between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceMinMaxDistanceSwitcherBinder _isNearRange;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isNearRange;
    }


Switch the AudioSource min/max distance between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private Vector2 _trueRange;
        
        [SerializeField]
        private Vector2 _falseRange;
        
        private AudioSourceMinMaxDistanceSwitcherBinder IsNearRange => new(
            _audioSource, _trueRange, _falseRange);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isNearRange;
    }
